	(1, 'register_form_update', 'нҡҢмӣҗк°Җмһ…', 'м•Ҳл…•н•ҳм„ёмҡ”. #{мқҙлҰ„}лӢҳ\r\nм§Җкө¬ліё нҡҢмӣҗмқҙ лҗҳмӢ кІғмқ„ м§„мӢ¬мңјлЎң нҷҳмҳҒн•©лӢҲлӢӨ.', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''),
	(2, 'orderformupdate', 'м ңн’ҲмЈјл¬ё', '#{мқҙлҰ„}лӢҳ мЈјл¬ён•ҙмЈјм…”м„ң кі л§ҷмҠөлӢҲлӢӨ.\r\n#{мЈјл¬ёлІҲнҳё}\r\n#{мЈјл¬ёкёҲм•Ў}мӣҗ\r\nм§Җкө¬ліё', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''),
	(4, 'order_payment_bank', 'мһ…кёҲнҷ•мқё', '#{мқҙлҰ„}лӢҳ мһ…кёҲ к°җмӮ¬н•©лӢҲлӢӨ.\r\n#{мһ…кёҲм•Ў}мӣҗ\r\nмЈјл¬ёлІҲнҳё:\r\n#{мЈјл¬ёлІҲнҳё}\r\nм§Җкө¬ліё', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''),
	(5, 'order_shipping', 'л°°мҶЎм•ҲлӮҙ', '#{мқҙлҰ„}лӢҳ л°°мҶЎн•©лӢҲлӢӨ.\r\nнғқл°°:#{нғқл°°нҡҢмӮ¬}\r\nмҡҙмҶЎмһҘлІҲнҳё:\r\n#{мҡҙмҶЎмһҘлІҲнҳё}\r\nм§Җкө¬ліё', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''),
	(6, 'orderbankinfo', 'мһ…кёҲмҡ”мІӯ', '#{мқҙлҰ„}лӢҳмқҳ мһ…кёҲкі„мўҢмһ…лӢҲлӢӨ.\r\n#{мһ…кёҲм•Ў}\r\n#{мһ…кёҲкі„мўҢ}\r\nм§Җкө¬ліё', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '');
