	(8, 'posttoadmin', 'кІҢмӢңкёҖм•ҢлҰј(кҙҖлҰ¬мһҗ)', 'м•Ҳл…•н•ҳм„ёмҡ”. кҙҖлҰ¬мһҗлӢҳ #{мқҙлІӨнҠё} л“ұлЎқлҗҳм—ҲмҠөлӢҲлӢӨ.\r\nм ңлӘ© : #{м ңлӘ©}\r\nм„ұлӘ… : #{мқҙлҰ„}\r\nнҺҳмқҙм§Җл°”лЎңк°Җкё° : #{м—°кІ°л§ҒнҒ¬}', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''),
