INSERT INTO `g5_autosave` (`as_id`, `mb_id`, `as_uid`, `as_subject`, `as_content`, `as_datetime`) VALUES
	(16, 'admin', 2024061409420047, '[кіөм§Җ] н…Җлё”лҹ¬&м§Җкө¬ліём»ө м§Җм°ё мӢң м „л©”лүҙ 1,000мӣҗ н• мқё', '<p style="text-align: center; " align="center"><img src="https://www.earthborn.co.kr/data/editor/2406/b5d87df69c073caee6d0165b437a6b39_1718325288_3839.jpg" title="b5d87df69c073caee6d0165b437a6b39_1718325288_3839.jpg"></p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center">м•Ҳл…•н•ҳм„ёмҡ”!</p><p style="text-align: center; " align="center">м§Җкө¬лҘј мғқк°Ғн•ҳлҠ” лІ мқҙм»ӨлҰ¬ м№ҙнҺҳ, м§Җкө¬ліёмһ…лӢҲлӢӨ +_+</p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center">л§ӨмһҘ л°©л¬ё мӢң, м§Җкө¬ліё н…Җлё”лҹ¬лҘј м§Җм°ён•ҳм—¬ л°©л¬ён•ҳл©ҙ</p><p style="text-align: center; " align="center">мқҢлЈҢлҘј л¬ҙл Ө 1000мӣҗмқҙлӮҳ н• мқён•ҙ мӨҖлӢӨлҠ” мӮ¬мӢӨ!!!!</p><p style="text-align: center; " align="center">лӢӨл“Ө м•Ңкі  кі„м…ЁлӮҳмҡ”???!!!</p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center">мһҗм„ён•ң лӮҙмҡ©мқҙ к¶ҒкёҲн•ҳмӢңлӢӨл©ҙ, м§ҖкёҲ лӢ№мһҘ м•„лһҳ л§ҒнҒ¬лҘј нҷ•мқён•ҙ мЈјм„ёмҡ”!!!!</p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center"><span style="font-size: 14pt;"><b><u><a href="https://blog.naver.com/earthborn105/223330041676" target="_self"><span style="color: rgb(0, 158, 37); background-color: rgb(222, 247, 229);"><u>вҳһ м§Җкө¬ліё н• мқё нҳңнғқ мһҗм„ёнһҲ м•Ңм•„ліҙкё° вҳң</u></span></a></u></b></span><br style="clear:both;">&nbsp;</p>', '2024-06-14 09:44:53');
INSERT INTO `g5_autosave` (`as_id`, `mb_id`, `as_uid`, `as_subject`, `as_content`, `as_datetime`) VALUES
	(17, 'admin', 2024061409552432, '[кіөм§Җ] мӢңк·ёлӢҲмІҳ нҒ¬лҰјм»Өн”ј лҸҷмҳҒмғҒ лҰ¬л·° мқҙлІӨнҠё', '<p style="text-align: center; " align="center"><img src="https://www.earthborn.co.kr/data/editor/2406/b5d87df69c073caee6d0165b437a6b39_1718326498_3072.jpg" title="b5d87df69c073caee6d0165b437a6b39_1718326498_3072.jpg"></p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center">м•Ҳл…•н•ҳм„ёмҡ”!</p><p style="text-align: center; " align="center">м§Җкө¬лҘј мғқк°Ғн•ҳлҠ” лІ мқҙм»ӨлҰ¬ м№ҙнҺҳ, м§Җкө¬ліёмһ…лӢҲлӢӨ +_+</p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center">м§Җкө¬ліёмқҳ лҢҖн‘ң мқҢлЈҢмқё мӢңк·ёлӢҲмІҳ нҒ¬лҰј м»Өн”јлҠ”,</p><p style="text-align: center; " align="center">м§Җкө¬ліёл§Ңмқҳ мӢңк·ёлӢҲмІҳ лё”л Ңл”© мӣҗл‘җлҘј</p><p style="text-align: center; " align="center">лҚ” к°Җк№Ңмқҙм—җм„ң лҠҗлҒјмӢӨ мҲҳ мһҲлҸ„лЎқ м ңмһ‘лҗң л©”лүҙлһҚлӢҲлӢӨ.</p><p style="text-align: center; " align="center"><br></p><p style="text-align: center; " align="center">м§„н•ҳкі  кі мҶҢн•ң м§Җкө¬ліё мӢңк·ёлӢҲмІҳ м»Өн”ј мң„лЎң мҳ¬лқјк°„</p><p style="text-align: center; " align="center">л¶Җл“ңлҹ¬мҡҙ мҪ”мҪ”л„ӣ нҒ¬лҰјкіј л°”мӮӯн•ң лІ мқҙкёҖ м№©мқҳ мЎ°н•©мқҖ</p><p style="text-align: center; " align="center">м–ём ң лЁ№м–ҙлҸ„&nbsp;</p>', '2024-06-14 10:04:24'),
	(24, 'nurii', 2025102316042319, '11PM мҝ нҸ° л“ңлЎӯ Event', '<div>л§Өмқј л°Ө 11мӢң, 15% &amp; 20% мҝ нҸ°мқҙ л–Ём–ҙм§‘лӢҲлӢӨ.</div><div>м•ҢлһҢ л§һм¶”кі , мӢ м„ н•ң н•ң мһ”мқ„ лҚ” к°ҖліҚкІҢ.</div><div><br></div><div><img src="http://cafemuin.com/data/editor/2510/12c015ca91c6a53e838c62e44607bb32_1761202276_049.jpg" title="12c015ca91c6a53e838c62e44607bb32_1761202276_049.jpg"><br style="clear:both;">&nbsp;</div>', '2025-10-23 16:05:23');
