INSERT INTO `g5_qa_content` (`qa_id`, `qa_num`, `qa_parent`, `qa_related`, `mb_id`, `qa_name`, `qa_email`, `qa_hp`, `qa_type`, `qa_category`, `qa_email_recv`, `qa_sms_recv`, `qa_html`, `qa_subject`, `qa_content`, `qa_status`, `qa_file1`, `qa_source1`, `qa_file2`, `qa_source2`, `qa_ip`, `qa_datetime`, `qa_1`, `qa_2`, `qa_3`, `qa_4`, `qa_5`) VALUES
	(6, -4, 6, 6, 'bianca0128', 'лҰ¬м•„', 'bianca01287794@gmail.com', '010-7794-7100', 0, 'м·ЁмҶҢ', 0, 0, 1, 'м·ЁмҶҢмӢ мІӯ', '<p>л°°мҶЎмқҙ м•Ҳлҗҳл„Өмҡ”?л№ лҘё м·ЁмҶҢ л¶ҖнғҒл“ңлҰҪлӢҲлӢӨ</p>', 0, '', '', '', '', '58.235.241.84', '2024-02-22 15:12:50', '', '', '', '', ''),
	(4, -3, 4, 4, 'kakao_994108fa', 'мқҙмҲҳл№Ҳ', 'subinlee0882@yonsei.ac.kr', '01091764063', 0, 'мһ…кёҲ', 0, 0, 1, 'л¬ҙнҶөмһҘ мһ…кёҲ кі„мўҢ', '<p>м•Ҳл…•н•ҳм„ёмҡ”!</p><p>м§ҖлӮң лІҲм—җ л¬ҙнҶөмһҘ мһ…кёҲмңјлЎң мғҒн’Ҳмқ„ мЈјл¬ён–ҲлҠ”лҚ°,</p><p>нҶөмһҘ кі„мўҢлІҲнҳёлһ‘ мҳҲкёҲмһҗ лӘ…мқҙ мҳӨлҘҳк°Җ мһҲлҠ” кІғ к°ҷм•„ мһ…кёҲмқ„ лӘ» н•ҳкі  мһҲм—ҲмҠөлӢҲлӢӨ.</p><p>нҳ№мӢң нҶөмһҘ кі„мўҢлІҲнҳёмҷҖ мҳҲкёҲмһҗ лӘ… лӢӨмӢң нҷ•мқён•ҙмЈјмӢӨ мҲҳ мһҲмқ„к№Ңмҡ”?</p>', 1, '', '', '', '', '165.132.5.143', '2024-01-23 17:01:53', '', '', '', '', ''),
	(5, -3, 4, 4, 'admin', 'м§Җкө¬ліё', '', '', 1, 'мһ…кёҲ', 0, 0, 1, 'м•Ҳл…•н•ҳм„ёмҡ” м§Җкө¬ліёмһ…лӢҲлӢӨ!', '<p>м•Ҳл…•н•ҳм„ёмҡ” м§Җкө¬ліёмһ…лӢҲлӢӨ.&nbsp;</p><p>м§Җкө¬ліё нҷҲнҺҳмқҙм§Җ н…ҢмҠӨнҠё кё°к°„мӨ‘м—җ кІ°м ңлҘј м§„н–үн•ҙмЈјмӢ кұёлЎң нҷ•мқёлҗҳм–ҙм„ңмҡ” г…ңг…ң</p><p><br></p><p>мҠӨл§ҲнҠёмҠӨнҶ м–ҙлЎң мһ¬кІ°м ң л¶ҖнғҒл“ңл ӨлҸ„лҗ к№Ңмҡ”&nbsp;</p><p>л№ лҘё мӢңк°„лӮҙм—җ нҷңм„ұнҷ” мӢңнӮӨкІ мҠөлӢҲлӢӨ.&nbsp;</p><p>кі л§ҷмҠөлӢҲлӢӨ^^&nbsp;</p>', 1, '', '', '', '', '218.156.1.209', '2024-01-26 16:24:25', '', '', '', '', '');
