	(28, -5, '', 28, 0, 0, '', 'нқ¬л§қк·ёлҰ° мҠӨнҶ лҰ¬', 'html1', 'м°Ё н•ң мһ”мқҳ мҳЁлҸ„, л§ҲмқҢмқҳ м—¬мң лҘј лӢҙлӢӨ', '<p><img src="http://cafemuin.com/data/editor/2510/12c015ca91c6a53e838c62e44607bb32_1761204436_7731.jpg" title="12c015ca91c6a53e838c62e44607bb32_1761204436_7731.jpg"></p><p><br></p><p><br></p><p>л°”мҒң н•ҳлЈЁ мҶҚм—җм„ңлҸ„, мһ мӢң л©Ҳм¶° м„Ө мҲңк°„мқҙ н•„мҡ”н•©лӢҲлӢӨ.</p><p>нқ¬л§қк·ёлҰ°мқҳ м°ЁлҠ” к·ё вҖҳл©Ҳм¶ӨвҖҷмқ„ мң„н•ҙ л§Ңл“Өм–ҙмЎҢмҠөлӢҲлӢӨ.</p><p><br></p><p>л§‘мқҖ кіөкё°мҷҖ к№ЁлҒ—н•ң л¬ј, к·ёлҰ¬кі  м •м§Ғн•ң мһҺл§Ңмқ„ кіЁлқј</p><p>мһҗм—°мқҙ ліёлһҳ м§ҖлӢҢ н–Ҙкіј мғүмқ„ к·ёлҢҖлЎң лӢҙм•ҳмҠөлӢҲлӢӨ.</p><p><br></p><p>м»өмқ„ к°җмӢёлҠ” л”°лң»н•ң мҳЁкё° мҶҚм—җм„ң</p><p>лӘёмқҙ лЁјм Җ лҠҗлҒјкі , л§ҲмқҢмқҙ мІңмІңнһҲ л”°лқјмҳөлӢҲлӢӨ.</p><p><br></p><p>н•ң лӘЁкёҲмқҳ м°Ёк°Җ н•ҳлЈЁлҘј лӢӨм •н•ҳкІҢ л°”кҫёл“Ҝ,</p><p>нқ¬л§қк·ёлҰ°мқҖ мҳӨлҠҳлҸ„ лӢ№мӢ мқҳ мқјмғҒм—җ мһ‘мқҖ нҸүнҷ”лҘј м „н•©лӢҲлӢӨ.</p><p><br></p><p>мһҗм—°мқҙ лЁёл¬ҙлҠ” н–Ҙкё°, нқ¬л§қк·ёлҰ° нӢ°.</p><p><br></p>', '', '', 0, 0, 236, 0, 0, 'nurii', '*98262BA8F657B02FA636168FC63D655196F5C151', 'мөңкі кҙҖлҰ¬мһҗ', 'nuri@nuri-i.co.kr', '', '2025-10-23 16:27:27', 1, '2025-10-23 16:27:27', '211.168.253.210', '', '', '', '', '', '', '', '', '', '', '', '', 0, 0, 0, 1, 0, 0, 0, 2, 0, 0, 0, 0, 0, 0, 0, 0, '', '', '', '', '', 'http://cafemuin.com/data/file/content/1c893a0fe93b7978435c1aceebcea1f0_9lxmzpOT_a02fc8abb908a898ad3005244dc56587a6a8e2bc.jpg', '', '0000-00-00 00:00:00', 0);
