	(21, -1, '', 21, 0, 0, '', 'мқҙлІӨнҠё', 'html1', '11PM мҝ нҸ° л“ңлЎӯ Event', '<div><div>л§Өмқј л°Ө 11мӢң, 15% &amp; 20% мҝ нҸ°мқҙ л–Ём–ҙм§‘лӢҲлӢӨ.</div><div>м•ҢлһҢ л§һм¶”кі , мӢ м„ н•ң н•ң мһ”мқ„ лҚ” к°ҖліҚкІҢ.</div></div><div><br></div><div><img src="http://cafemuin.com/data/editor/2510/12c015ca91c6a53e838c62e44607bb32_1761202276_049.jpg" title="12c015ca91c6a53e838c62e44607bb32_1761202276_049.jpg"></div><div><br></div><div><div><br></div>&nbsp;</div>', '', '', 1, 0, 308, 0, 0, 'nurii', '*98262BA8F657B02FA636168FC63D655196F5C151', 'мөңкі кҙҖлҰ¬мһҗ', 'nuri@nuri-i.co.kr', '', '2025-10-23 13:59:04', 1, '2025-10-23 13:59:04', '211.168.253.210', '', '', '', '', '', '', '', '', '', '', '', '', 0, 0, 0, 1, 0, 0, 0, 2, 0, 0, 0, 0, 0, 0, 0, 0, '', '', '', '', '', 'http://cafemuin.com/data/editor/2510/12c015ca91c6a53e838c62e44607bb32_1761202276_049.jpg', '', '0000-00-00 00:00:00', 0);
