	(25, -2, '', 25, 0, 0, '', 'мқҙлІӨнҠё', 'html1', 'Free Shipping Week', '<p>м§ҖкёҲмқҖ л°°мҶЎл№„ 0мӣҗмқҳ кё°нҡҢ!</p><p>нқ¬л§қк·ёлҰ°мӢқн’Ҳмқҳ м»Өн”јмҷҖ лқјл–јлЎң лӢ№мӢ мқҳ н•ҳлЈЁлҘј мғҲлЎӯкІҢ мұ„мӣҢліҙм„ёмҡ”.</p><p><br></p><p><img src="http://cafemuin.com/data/editor/2510/12c015ca91c6a53e838c62e44607bb32_1761204138_708.jpg" title="12c015ca91c6a53e838c62e44607bb32_1761204138_708.jpg"><br style="clear:both;">&nbsp;</p><p><br></p><p><br></p>', '', '', 0, 0, 324, 0, 0, 'nurii', '*98262BA8F657B02FA636168FC63D655196F5C151', 'мөңкі кҙҖлҰ¬мһҗ', 'nuri@nuri-i.co.kr', '', '2025-10-23 16:22:24', 1, '2025-10-23 16:22:24', '211.168.253.210', '', '', '', '', '', '', '', '', '', '', '', '', 0, 0, 0, 1, 0, 0, 0, 2, 0, 0, 0, 0, 0, 0, 0, 0, '', '', '', '', '', 'http://cafemuin.com/data/file/content/1c893a0fe93b7978435c1aceebcea1f0_bDRZWolH_80fbab95c3b881d4f0c0ee2a9ebab4f769cb5731.jpg', '', '0000-00-00 00:00:00', 0);
