	(26, -3, '', 26, 0, 0, '', 'мқҙлІӨнҠё', 'html1', 'мІ« л§ҢлӮЁ, нҠ№лі„н•ң нҳңнғқмңјлЎң', '<p>м§ҖкёҲ мІ« кө¬л§Ө мӢң 20% н• мқёмҝ нҸ° + 5,000P + м»Өн”ј кё°н”„нӢ°мҪҳ мҰқм •!</p><p><br></p><p>м§ҖкёҲ к°Җмһ…н•ҳкі , мӢ м„ н•Ёкіј нҳңнғқмқ„ н•ң лІҲм—җ лҲ„л Өліҙм„ёмҡ”.</p><p>мҳӨлҠҳ, лӢ№мӢ мқҳ мғҲлЎңмҡҙ м»Өн”ј лЈЁнӢҙмқҙ мӢңмһ‘лҗ©лӢҲлӢӨ.</p><p><br></p><p><br></p><p><img src="http://cafemuin.com/data/editor/2510/12c015ca91c6a53e838c62e44607bb32_1761204179_2183.jpg" title="12c015ca91c6a53e838c62e44607bb32_1761204179_2183.jpg"></p><p><br></p><p><br></p>', '', '', 0, 0, 202, 0, 0, 'nurii', '*98262BA8F657B02FA636168FC63D655196F5C151', 'мөңкі кҙҖлҰ¬мһҗ', 'nuri@nuri-i.co.kr', '', '2025-10-23 16:23:13', 1, '2025-10-23 16:23:13', '211.168.253.210', '', '', '', '', '', '', '', '', '', '', '', '', 0, 0, 0, 1, 0, 0, 0, 2, 0, 0, 0, 0, 0, 0, 0, 0, '', '', '', '', '', 'http://cafemuin.com/data/file/content/1c893a0fe93b7978435c1aceebcea1f0_zxEfdB2c_77da4f4b86078c842cb95a240bacbc11d5589e26.jpg', '', '0000-00-00 00:00:00', 0);
